317	      purpose:
318	        "Drains the upload queue (extract, transcribe, claims), refreshes Currents, materializes Ops rollups.",
319	    },
320	    {
321	      name: "Build & deploy founder portal",
322	      file: ".github/workflows/build-founder-portal.yml",
323	      url: `${base}/build-founder-portal.yml`,
324	      cadence: "on push / manual",
325	      purpose: "Builds the Next.js founder portal image.",
326	    },
327	    {
328	      name: "Build Noosphere container",
329	      file: ".github/workflows/build-noosphere.yml",
330	      url: `${base}/build-noosphere.yml`,
331	      cadence: "on push / manual",
332	      purpose: "Builds the Noosphere worker image used by the always-on scheduler.",
333	    },
334	    {
335	      name: "Forecasts CI",
336	      file: ".github/workflows/forecasts-ci.yml",
337	      url: `${base}/forecasts-ci.yml`,
338	      cadence: "on push / pull request",
339	      purpose: "Smoke-tests the forecasts portfolio service.",
340	    },
341	    {
342	      name: "Nightly replication",
343	      file: ".github/workflows/nightly_replication.yml",
344	      url: `${base}/nightly_replication.yml`,
345	      cadence: "nightly cron",
346	      purpose: "Snapshots the Codex DB for offline reanalysis.",
347	    },
348	  ];
349	}
