351	export async function loadOpsHealth(tenant: TenantContext): Promise<OpsHealth> {
352	  const [
353	    uploads,
354	    traces,
355	    alerts,
356	    embedding,
357	    currents,
358	  ] = await Promise.all([
359	    loadUploadHealth(tenant.organizationId),
360	    loadTraceHealth(),
361	    loadAlertHealth(),
362	    embeddingHealth(tenant.organizationId).catch((err) => {
363	      console.error("ops_health_embedding_failed", err);
364	      return null as EmbeddingHealth | null;
365	    }),
366	    loadCurrentsBackend(),
367	  ]);
368	  const autoProcessing = loadAutoProcessingEnv();
369	  const workflows = workflowCatalog(autoProcessing.githubDispatchRepo);
370	
371	  // We can't introspect the scheduler container from Vercel directly,
372	  // but a recent successful Currents cycle is good evidence the
373	  // always-on loop is alive. A reachable backend with `last_cycle_at`
374	  // inside the last hour ⇒ provisioned. Otherwise unknown — never
375	  // assert "fixed".
376	  let schedulerProvisioned: boolean | "unknown" = "unknown";
377	  if (currents.reachable && currents.health?.last_cycle_at) {
378	    const last = Date.parse(currents.health.last_cycle_at);
379	    if (Number.isFinite(last)) {
380	      schedulerProvisioned = Date.now() - last < 60 * 60 * 1000;
381	    }
382	  } else if (!currents.reachable) {
383	    schedulerProvisioned = false;
384	  }
385	
386	  return {
387	    generatedAt: new Date(),
388	    uploads,
389	    traces,
390	    alerts,
391	    embedding,
392	    currents,
393	    autoProcessing,
394	    workflows,
395	    schedulerProvisioned,
396	  };
397	}
398	
399	export const STALE_THRESHOLD_MINUTES = STALE_MINUTES;
